// Usage pattern:
const error = validateFilter("name=='test'", "portfolio.projects");
if (error) return errorResponse(error);

// Validation pattern:
const keys = args.triage_properties.map(p => p.key);
if (keys.includes('is-dismissed')) {
  return errorResponse("Cannot set 'is-dismissed' — it is auto-calculated. To dismiss, use {dismissal-reason, comment} instead.");
}
if (keys.includes('status') && keys.includes('dismissal-reason')) {
  return errorResponse("Cannot set both 'status' and 'dismissal-reason'. To dismiss: use {dismissal-reason, comment}. To change status: use {status, comment}.");
}
